645	const RUNNER_TYPE_MAX = 64;
646	const RUNNER_TYPE_RE = /^[a-z0-9-]+$/;
647	
648	// Mirrored from packages/agents/src/store.ts. Cross-plugin imports are
649	// forbidden (CLAUDE.md invariant #2); duplicating two lines is cheaper
650	// than a shared package. Keep the values in lockstep when the upstream
651	// changes.
652	const FROZEN_WORKSPACE_REF_MAX = 256;
653	const FROZEN_WORKSPACE_REF_RE = /^[A-Za-z0-9_./-]+$/;
654	
655	export function validateRunnerType(value: unknown): string | null {
656	  if (value === null || value === undefined) return null;
657	  if (typeof value !== 'string') {
658	    throw invalid('runnerType must be a string or null');
659	  }
660	  if (value.length === 0 || value.length > RUNNER_TYPE_MAX) {
661	    throw invalid(`runnerType must be 1-${RUNNER_TYPE_MAX} chars`);
662	  }
663	  if (!RUNNER_TYPE_RE.test(value)) {
664	    throw invalid(`runnerType must match ${RUNNER_TYPE_RE.source}`);
665	  }
666	  return value;
667	}
