import { describe, it, expect, beforeAll, afterAll, afterEach } from 'vitest';
import {
  PostgreSqlContainer,
  type StartedPostgreSqlContainer,
} from '@testcontainers/postgresql';
import { PluginError } from '@ax/core';
import { createTestHarness, type TestHarness } from '@ax/test-harness';
import { createDatabasePostgresPlugin } from '@ax/database-postgres';
import { createConversationsPlugin } from '../plugin.js';
import type {
  AppendTurnInput,
  AppendTurnOutput,
  CreateInput,
  CreateOutput,
  DeleteInput,
  GetByReqIdInput,
  GetByReqIdOutput,
  GetInput,
  GetOutput,
  ListInput,
  ListOutput,
} from '../types.js';

// ---------------------------------------------------------------------------
// ACL gate test — every conversations:* hook MUST call agents:resolve
// before touching the store (Invariant J1). We mock agents:resolve via a
// programmable handler so each test can declare exactly which (agentId,
// userId) tuples are reachable.
// ---------------------------------------------------------------------------

interface MockResolveCall {
  agentId: string;
  userId: string;
}

interface MockResolvePolicy {
  /**
   * Return value:
   *   - 'allow'    → resolve succeeds (returns a stub agent).
   *   - 'forbid'   → resolve throws PluginError code='forbidden'.
   *   - 'notfound' → resolve throws PluginError code='not-found'.
   */
  decide(call: MockResolveCall): 'allow' | 'forbid' | 'notfound';
}

let container: StartedPostgreSqlContainer;
let connectionString: string;
const harnesses: TestHarness[] = [];

async function setReqIdViaStore(
  _h: TestHarness,
  conversationId: string,
  reqId: string | null,
): Promise<void> {
  // Task 14 will own active_req_id via `conversations:bind-session`;
  // until then, raw SQL through pg.Client is the simplest fixture.
  const client = new (await import('pg')).default.Client({ connectionString });
  await client.connect();
  try {
    await client.query(
      'UPDATE conversations_v1_conversations SET active_req_id = $1, updated_at = NOW() WHERE conversation_id = $2',
      [reqId, conversationId],
    );
  } finally {
    await client.end().catch(() => {});
  }
}

async function makeHarness(policy: MockResolvePolicy): Promise<{
  h: TestHarness;
  calls: MockResolveCall[];
}> {
  const calls: MockResolveCall[] = [];
  const h = await createTestHarness({
    services: {
      'agents:resolve': async (
        _ctx,
        input: unknown,
      ): Promise<{ agent: { id: string; visibility: string } }> => {
        const call = input as MockResolveCall;
        calls.push(call);
        const decision = policy.decide(call);
        if (decision === 'allow') {
          return {
            agent: { id: call.agentId, visibility: 'personal' },
          };
        }
        if (decision === 'notfound') {
          throw new PluginError({
            code: 'not-found',
            plugin: 'mock-agents',
            hookName: 'agents:resolve',
            message: `agent '${call.agentId}' not found`,
          });
        }
        throw new PluginError({
          code: 'forbidden',
          plugin: 'mock-agents',
          hookName: 'agents:resolve',
          message: `agent '${call.agentId}' not accessible to '${call.userId}'`,
        });
      },
    },
    plugins: [
      createDatabasePostgresPlugin({ connectionString }),
      createConversationsPlugin(),
    ],
  });
  harnesses.push(h);
  return { h, calls };
}

beforeAll(async () => {
  container = await new PostgreSqlContainer('postgres:16-alpine').start();
  connectionString = container.getConnectionUri();
}, 120_000);

afterEach(async () => {
  while (harnesses.length > 0) {
    const h = harnesses.pop()!;
    await h.close({ onError: () => {} });
  }
  // Drop tables so each test starts fresh.
  const cleanup = new (await import('pg')).default.Client({ connectionString });
  await cleanup.connect();
  try {
    await cleanup.query('DROP TABLE IF EXISTS conversations_v1_turns');
    await cleanup.query('DROP TABLE IF EXISTS conversations_v1_conversations');
  } finally {
    await cleanup.end().catch(() => {});
  }
});

afterAll(async () => {
  if (container) await container.stop();
});

describe('@ax/conversations ACL gate', () => {
  it('every hook calls agents:resolve before touching the store', async () => {
    // Allow everything. We assert that BOTH create and append-turn fire
    // an agents:resolve call so a future regression that bypasses the
    // gate breaks this test.
    const { h, calls } = await makeHarness({
      decide: () => 'allow',
    });

    const created = await h.bus.call<CreateInput, CreateOutput>(
      'conversations:create',
      h.ctx({ userId: 'userA' }),
      { userId: 'userA', agentId: 'agt_a' },

import { sql, type Kysely } from 'kysely';

/**
 * Per-plugin migration. @ax/conversations owns tables under the
 * `conversations_v1_` prefix — never reach into them from another plugin
 * (Invariant I4 — one source of truth per concept). Schema version is
 * forward-only via a future `v2` side-table, never an in-place ALTER.
 *
 * Tables:
 *   conversations_v1_conversations  — conversation entity, owned by user_id.
 *   conversations_v1_turns          — append-only turn log per conversation.
 *
 * No FK to auth_v1_users / agents_v1_agents. Cross-plugin FKs would
 * require shared schema migrations, which violates I4 (no shared rows).
 * The runtime ACL gate (`agents:resolve`) checks ownership against the
 * live row at hook time; orphan conversation rows after a user/agent
 * delete are tolerable (they simply fail every `conversations:get` /
 * `:append-turn` and can be GC'd later).
 *
 * Soft delete:
 *   `deleted_at` is nullable. The owner index excludes tombstones via a
 *   partial WHERE clause so list-by-user is fast even with large numbers
 *   of soft-deleted rows.
 *
 * Turn ordering:
 *   `(conversation_id, turn_index)` is UNIQUE — `appendTurn` retries on
 *   23505 unique-violation if a concurrent insert wins the index.
 */
// Schema-agnostic: the executor only needs to issue raw DDL.
export async function runConversationsMigration<DB>(
  db: Kysely<DB>,
): Promise<void> {
  await sql`
    CREATE TABLE IF NOT EXISTS conversations_v1_conversations (
      conversation_id TEXT PRIMARY KEY,
      user_id TEXT NOT NULL,
      agent_id TEXT NOT NULL,
      title TEXT,
      active_session_id TEXT,
      active_req_id TEXT,
      deleted_at TIMESTAMPTZ,
      created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
      updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
    )
  `.execute(db);

  await sql`
    CREATE INDEX IF NOT EXISTS conversations_v1_conversations_owner
      ON conversations_v1_conversations (user_id, agent_id)
      WHERE deleted_at IS NULL
  `.execute(db);

  await sql`
    CREATE TABLE IF NOT EXISTS conversations_v1_turns (
      turn_id TEXT PRIMARY KEY,
      conversation_id TEXT NOT NULL,
      turn_index INTEGER NOT NULL,
      role TEXT NOT NULL,
      content_blocks JSONB NOT NULL,
      created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
      CONSTRAINT conversations_v1_turns_role_check
        CHECK (role IN ('user', 'assistant', 'tool')),
      UNIQUE (conversation_id, turn_index)
    )
  `.execute(db);

  await sql`
    CREATE INDEX IF NOT EXISTS conversations_v1_turns_lookup
      ON conversations_v1_turns (conversation_id, turn_index)
  `.execute(db);
}

/**
 * Row shapes — JSONB columns deserialize to `unknown` until validated.
 * Store helpers parse/validate before returning to plugin code.
 */
export interface ConversationsRow {
  conversation_id: string;
  user_id: string;
  agent_id: string;
  title: string | null;
  active_session_id: string | null;
  active_req_id: string | null;
  deleted_at: Date | null;
  created_at: Date;
  updated_at: Date;
}

export interface TurnsRow {
  turn_id: string;
  conversation_id: string;
  turn_index: number;
  role: string;
  content_blocks: unknown;
  created_at: Date;
}

export interface ConversationDatabase {
  conversations_v1_conversations: ConversationsRow;
  conversations_v1_turns: TurnsRow;
}

