16	} from './types.js';
17	
18	// Array-of-blocks parser — used at every store ingress AND egress (we don't
19	// trust the JSONB column blindly; the same canonical schema validates on
20	// both sides of the DB boundary).
21	const ContentBlockArraySchema = z.array(ContentBlockSchema);
22	
23	const PLUGIN_NAME = '@ax/conversations';
24	
25	// ---------------------------------------------------------------------------
26	// Validation helpers — caller-supplied strings are bounded BEFORE INSERT.
27	// The DB has a CHECK on role; everything else is enforced here because
28	// length limits don't translate cleanly to SQL.
29	// ---------------------------------------------------------------------------
30	
31	const TITLE_MAX = 256;
32	const VALID_ROLES: ReadonlySet<TurnRole> = new Set([
33	  'user',
34	  'assistant',
35	  'tool',
36	]);
37	
38	function invalid(message: string): PluginError {
39	  return new PluginError({
40	    code: 'invalid-payload',
41	    plugin: PLUGIN_NAME,
42	    message,
43	  });
44	}
45	
46	export function validateTitle(value: unknown): string | null {
47	  if (value === null || value === undefined) return null;
48	  if (typeof value !== 'string') {
49	    throw invalid('title must be a string or null');
50	  }
51	  if (value.length === 0 || value.length > TITLE_MAX) {
52	    throw invalid(`title must be 1-${TITLE_MAX} chars`);
53	  }
54	  return value;
55	}
56	
57	export function validateRole(value: unknown): TurnRole {
58	  if (typeof value !== 'string' || !VALID_ROLES.has(value as TurnRole)) {
59	    throw invalid("role must be 'user', 'assistant', or 'tool'");
60	  }
61	  return value as TurnRole;
62	}
63	
64	export function validateContentBlocks(value: unknown): ContentBlock[] {
65	  // Canonical Anthropic-compatible schema lives in @ax/ipc-protocol; this
66	  // is the single source of truth for both the IPC wire and our JSONB
67	  // column (Invariant I4).
68	  const parsed = ContentBlockArraySchema.safeParse(value);
69	  if (!parsed.success) {
70	    throw invalid(
71	      `contentBlocks must be an array of ContentBlock objects: ${parsed.error.message}`,
72	    );
73	  }
74	  return parsed.data;
75	}
76	
77	// ---------------------------------------------------------------------------
78	// ID minting — `crypto.randomBytes`-derived prefixed ids, mirroring the
79	// `agt_` / `usr_` posture in @ax/agents and @ax/auth-oidc.
80	// ---------------------------------------------------------------------------
81	
82	export function mintConversationId(): string {
83	  return `cnv_${randomBytes(16).toString('base64url')}`;
84	}
85	
86	export function mintTurnId(): string {
87	  return `trn_${randomBytes(16).toString('base64url')}`;
88	}
89	
90	// ---------------------------------------------------------------------------
91	// Row → domain mapping. Defensive — JSONB columns return parsed JS values
92	// from `pg`'s default casts; we narrow them before exposing.
93	// ---------------------------------------------------------------------------
94	
95	function rowToConversation(row: ConversationsRow): Conversation {
96	  return {
97	    conversationId: row.conversation_id,
98	    userId: row.user_id,
99	    agentId: row.agent_id,
100	    title: row.title,
101	    activeSessionId: row.active_session_id,
102	    activeReqId: row.active_req_id,
103	    createdAt: row.created_at.toISOString(),
104	    updatedAt: row.updated_at.toISOString(),
105	  };
106	}
107	
108	function rowToTurn(row: TurnsRow): Turn {
109	  // We don't trust the DB blindly — JSONB columns can drift across schema
110	  // changes, replication hiccups, manual SQL, or future migrations. The
111	  // canonical ContentBlockSchema validates on read AND write so the type
112	  // promise we make to consumers stays honest.
113	  const parsedBlocks = ContentBlockArraySchema.safeParse(row.content_blocks);
114	  if (!parsedBlocks.success) {
115	    throw new PluginError({
116	      code: 'corrupt-row',
117	      plugin: PLUGIN_NAME,
118	      message: `conversations_v1_turns.${row.turn_id} has invalid content_blocks JSONB: ${parsedBlocks.error.message}`,
119	    });
120	  }
121	  if (
122	    row.role !== 'user' &&
123	    row.role !== 'assistant' &&
124	    row.role !== 'tool'
125	  ) {
126	    throw new PluginError({
127	      code: 'corrupt-row',
128	      plugin: PLUGIN_NAME,
129	      message: `conversations_v1_turns.${row.turn_id} has invalid role`,
130	    });
131	  }
132	  return {
133	    turnId: row.turn_id,
134	    turnIndex: row.turn_index,
135	    role: row.role,
136	    contentBlocks: parsedBlocks.data,
137	    createdAt: row.created_at.toISOString(),
138	  };
139	}
140	
141	// ---------------------------------------------------------------------------
142	// Store API. The plugin's hook handlers call into this; the lint rule
143	// `local/no-bare-tenant-tables` enforces that bare `selectFrom` against
144	// `conversations_v1_*` only happens inside this file (or scope.ts /
145	// tests).
146	// ---------------------------------------------------------------------------
147	
148	export interface ConversationStoreCreateArgs {
149	  userId: string;
150	  agentId: string;
151	  title: string | null;
152	}
153	
154	export interface ConversationStoreAppendTurnArgs {
155	  conversationId: string;
156	  role: TurnRole;
157	  contentBlocks: ContentBlock[];
158	}
159	
160	export interface ConversationStore {
161	  /** Single-row lookup; skips tombstones. Used in hook handlers after agents:resolve. */
162	  getByIdNotDeleted(conversationId: string): Promise<Conversation | null>;
163	  /**
164	   * Lookup a non-tombstoned conversation by `(user_id, active_req_id)`.
165	   * Returns null if no row matches OR the row is tombstoned. Used by the
166	   * `conversations:get-by-req-id` hook (Week 10–12 Task 7, Invariant J9).
167	   */
168	  getByReqIdForUser(
169	    userId: string,
170	    reqId: string,
171	  ): Promise<Conversation | null>;
172	  /** Multi-row reads always go through scopedConversations(). */
173	  listForUser(userId: string, agentId?: string): Promise<Conversation[]>;
174	  /** Read all turns for a conversation in turn_index order. */
175	  listTurns(conversationId: string): Promise<Turn[]>;
176	  create(args: ConversationStoreCreateArgs): Promise<Conversation>;
177	  appendTurn(args: ConversationStoreAppendTurnArgs): Promise<Turn>;
178	  /** Soft delete — sets deleted_at on the matching row. Idempotent: returns false on missing/already-deleted. */
179	  softDelete(conversationId: string): Promise<boolean>;
180	  /**
181	   * Set `active_session_id` + `active_req_id` atomically on the row
182	   * matching `(conversationId, userId)`. Returns true if a non-tombstoned
183	   * row was updated, false otherwise (including foreign-user rows). The
184	   * plugin-level handler turns false into PluginError('not-found') (J6).
185	   */
186	  setActiveSession(args: {
187	    conversationId: string;
188	    userId: string;
189	    sessionId: string;
190	    reqId: string;
191	  }): Promise<boolean>;
192	  /**
193	   * Clear `active_session_id` + `active_req_id` on the row matching
194	   * `(conversationId, userId)`. Returns true if a non-tombstoned row was
195	   * updated, false otherwise.
196	   */
197	  clearActiveSession(args: {
198	    conversationId: string;
199	    userId: string;
200	  }): Promise<boolean>;
201	  /**
202	   * Compare-and-clear `active_req_id` on the row matching `conversationId`
203	   * IFF the current `active_req_id` equals `expectedReqId`. Used by the
204	   * `chat:turn-end` subscriber so a stale callback (turn-end for r1
205	   * arrives after a fresh r2 has been bound) does NOT clobber the
206	   * newer in-flight reqId. `active_session_id` is left untouched (J6:
207	   * the sandbox stays alive for the next user message).
208	   *
209	   * Returns true if a row was updated, false otherwise (mismatched
210	   * reqId, tombstoned, or already null).
211	   */
212	  clearActiveReqId(
213	    conversationId: string,
214	    expectedReqId: string,
215	  ): Promise<boolean>;
216	  /**
217	   * Host-internal: clear `active_session_id` + `active_req_id` on EVERY
218	   * conversation bound to `sessionId`. Triggered by the `session:terminate`
219	   * subscriber — there's no userId scope because the host is observing
220	   * a sandbox teardown, not acting on behalf of a tenant. By J6 / I4 the
221	   * "many conversations bound to one sessionId" case shouldn't normally
222	   * happen, but a defensive multi-row clear is correct: if the session is
223	   * gone, no conversation may keep an active_req_id pointing at it.
224	   *
225	   * Returns the number of rows updated (0+).
226	   */
227	  clearBySessionId(sessionId: string): Promise<number>;
228	}
