1	import type { ContentBlock } from '@ax/ipc-protocol';
2	import { ContentBlockSchema } from '@ax/ipc-protocol';
3	
4	/**
5	 * @ax/conversations public types.
6	 *
7	 * Per Invariant I1, no field name in this file should ever encode a
8	 * particular backend (no `pg_`, `bucket_`, `sha`, `pod_name`, etc.). The
9	 * canonical alternate impl we keep in mind is `@ax/conversations-sqlite`
10	 * for single-replica dev.
11	 *
12	 * Hook payload shapes are the inter-plugin API. A future
13	 * `@ax/conversations-sqlite` would register the same `conversations:*`
14	 * service hooks with these exact shapes.
15	 */
16	
17	// ---------------------------------------------------------------------------
18	// ContentBlock — single source of truth lives in @ax/ipc-protocol (I4).
19	//
20	// Both the IPC wire (event.turn-end) and our JSONB column carry the same
21	// shape, so the canonical zod schema lives in the one place both plugins
22	// already share. We re-export here so existing `@ax/conversations`
23	// consumers don't have to reach across packages for the type.
24	// ---------------------------------------------------------------------------
25	export { ContentBlockSchema };
26	export type { ContentBlock };
27	
28	// ---------------------------------------------------------------------------
29	// Domain types — exposed on hook payloads.
30	// ---------------------------------------------------------------------------
31	
32	export type TurnRole = 'user' | 'assistant' | 'tool';
33	
34	export interface Turn {
35	  turnId: string;
36	  turnIndex: number;
37	  role: TurnRole;
38	  /**
39	   * Content blocks. Strongly typed at the package boundary; the store still
40	   * runtime-parses against `ContentBlockSchema` on read AND write so we
41	   * don't trust the DB blindly (Invariant I5 — capabilities-minimized,
42	   * untrusted-content-stays-untrusted).
43	   */
44	  contentBlocks: ContentBlock[];
45	  /** ISO-8601 string. */
46	  createdAt: string;
47	}
48	
49	export interface Conversation {
50	  conversationId: string;
51	  userId: string;
52	  /** Frozen at create (Invariant I10). Never updated. */
53	  agentId: string;
54	  /** Nullable; MVP doesn't auto-generate. */
55	  title: string | null;
56	  /** Nullable; cleared in Task 14. */
57	  activeSessionId: string | null;
58	  /** Nullable; the in-flight reqId, if any (Invariant J7). */
59	  activeReqId: string | null;
60	  /** ISO-8601 string. */
61	  createdAt: string;
62	  /** ISO-8601 string. */
63	  updatedAt: string;
64	}
65	
66	// ---------------------------------------------------------------------------
67	// Service hook payloads.
68	//
69	// Every hook is gated by a `agents:resolve(agentId, userId)` call BEFORE
70	// touching the store (Invariant J1). On `forbidden` / `not-found` from
71	// `agents:resolve` we propagate the matching `PluginError` code.
72	// ---------------------------------------------------------------------------
73	
74	export interface CreateInput {
75	  userId: string;
76	  agentId: string;
77	  /** Optional title — MVP leaves it null. */
78	  title?: string | null;
79	}
80	export type CreateOutput = Conversation;
81	
82	export interface AppendTurnInput {
83	  conversationId: string;
84	  /**
85	   * The user this turn belongs to. The `agents:resolve` gate uses this
86	   * to authorize the write against the conversation's frozen agent_id.
87	   */
88	  userId: string;
89	  role: TurnRole;
90	  contentBlocks: ContentBlock[];
91	}
92	export type AppendTurnOutput = Turn;
93	
94	export interface GetInput {
95	  conversationId: string;
96	  userId: string;
97	  /**
98	   * Reserved for Task 21 thinking-block UI toggle (Invariant J4). The
99	   * store unconditionally returns whatever blocks were appended; this
100	   * flag is forwarded to consumers but does NOT filter at the hook
101	   * boundary.
102	   */
103	  includeThinking?: boolean;
104	}
105	export interface GetOutput {
106	  conversation: Conversation;
107	  turns: Turn[];
108	}
109	
110	export interface ListInput {
111	  userId: string;
112	  /**
113	   * Optional filter — when set, only conversations under this agent are
114	   * returned. When absent, list returns every conversation the user
115	   * owns; ACL is implicit via `user_id` filter.
116	   */
117	  agentId?: string;
118	}
119	export type ListOutput = Conversation[];
120	
121	export interface DeleteInput {
122	  conversationId: string;
123	  userId: string;
124	}
125	/** Soft delete (Invariant J5). No payload — caller sees void on success. */
126	export type DeleteOutput = void;
127	
128	/**
129	 * Lookup a conversation by its in-flight `active_req_id`. Used by
130	 * channel-web's SSE handler (Week 10–12 Task 7, Invariant J9) so a
131	 * browser-supplied `:reqId` URL param can be authorized — callers MUST
132	 * own the row (filtered by `user_id`), and tombstones (`deleted_at IS
133	 * NULL`) are excluded.
134	 *
135	 * Throws `PluginError({ code: 'not-found' })` when no matching row
136	 * exists. The route layer maps that to 404 (NOT 403) — guessing a
137	 * foreign reqId leaks no signal beyond "no such stream."
138	 *
139	 * NOTE: this hook does NOT call `agents:resolve` (J1 gate). The caller
140	 * is expected to chain a follow-up `agents:resolve(agentId, userId)`
141	 * with the returned `agentId`. Two reasons:
142	 *
143	 *   1. The user already passes the `user_id` filter, so existence-leak
144	 *      is already prevented at this hook's boundary.
145	 *   2. Some callers (audit, debug probes) want the lookup without
146	 *      forcing the gate; making it explicit at the call site keeps
147	 *      the policy decision visible.
148	 */
149	export interface GetByReqIdInput {
150	  reqId: string;
151	  userId: string;
152	}
153	export type GetByReqIdOutput = Conversation;
154	
155	/**
156	 * Bind a sandbox session + in-flight reqId to a conversation row. Sets
157	 * BOTH `active_session_id` AND `active_req_id` atomically (J6: one
158	 * sandbox session per conversation at a time).
159	 *
160	 * Caller is the chat-orchestrator (Task 16) which has already validated
161	 * the user via `agents:resolve` at `agent:invoke` entry. This hook does NOT
162	 * call `agents:resolve`, but it DOES scope the row by `(conversation_id,
163	 * user_id)` derived from `ctx.userId` — a misbehaving caller cannot bind
164	 * a cross-tenant row.
165	 *
166	 * On a row not matching `(conversation_id, ctx.userId)` (and not
167	 * tombstoned), throws `PluginError({ code: 'not-found' })`.
168	 */
169	export interface BindSessionInput {
170	  conversationId: string;
171	  sessionId: string;
172	  reqId: string;
173	}
174	export type BindSessionOutput = void;
175	
176	/**
177	 * Clear `active_session_id` AND `active_req_id` on the conversation row.
178	 * Same `(conversation_id, ctx.userId)` scoping as `bind-session`. Throws
179	 * `PluginError({ code: 'not-found' })` on a row mismatch.
180	 *
181	 * The host-internal `session:terminate` subscriber takes a different
182	 * path (`store.clearBySessionId`) since it must clear ALL conversations
183	 * bound to a sessionId regardless of owner.
184	 */
185	export interface UnbindSessionInput {
186	  conversationId: string;
187	}
188	export type UnbindSessionOutput = void;
189	
190	/**
191	 * Fetch the persisted turn history for a conversation, formatted for
192	 * runner replay (Week 10–12 Task 15, Invariant J3 + J6 resume).
193	 *
194	 * The output strips `turnId` / `turnIndex` / `createdAt` from the full
195	 * `Turn` shape — replay into the SDK's prompt iterator only needs role
196	 * + content blocks, and a smaller payload keeps the wire surface tight.
197	 *
198	 * ACL: same `(user_id, agent_id)` gate as `conversations:get` (J1). A
199	 * caller that doesn't own the row gets `PluginError({ code: 'not-found' })`
200	 * — the same not-found-instead-of-forbidden posture as elsewhere, so a
201	 * tenant-id guess leaks no signal.
202	 */
203	export interface FetchHistoryInput {
204	  conversationId: string;
205	  userId: string;
206	}
207	export interface FetchHistoryTurn {
208	  role: TurnRole;
209	  contentBlocks: ContentBlock[];
210	}
211	export interface FetchHistoryOutput {
212	  turns: FetchHistoryTurn[];
213	}
214	
