   * on every non-heartbeat turn. Opaque to correctness; sidebar ordering
   * only. Null for pre-Phase-B rows or rows that haven't seen a turn.
   */
  lastActivityAt: string | null;
  /** ISO-8601 string. */
  createdAt: string;
  /** ISO-8601 string. */
  updatedAt: string;
